#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {            long long n;     cin >> n;    long long a[n];     for (int i = 0; i < n; i++) {        cin >> a[i];     }    map<long long, long long> fmap;    for (int i = 0; i < n; i++){        fmap[a[i]]++;        }    if (fmap.size() >= 3) {        cout << "No" << endl;     }    else{        long long freq_1 = fmap.begin()->second;        long long freq_2 = fmap.rbegin()->second;        if (freq_1 == freq_2) {                cout << "Yes" << endl;            }             else if (n % 2 == 1 && abs(freq_1 - freq_2) == 1)                 cout << "Yes" << endl;             else{                cout << "No" << endl;             }                            } } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}